package main

import (
    "fmt"
    "sync"
    "time"
)

func main() {
    // ---- Basic WaitGroup ----
    var wg sync.WaitGroup

    // ---- Add goroutines to wait for ----
    wg.Add(3)

    go func() {
        defer wg.Done()
        fmt.Println("Goroutine 1 started")
        time.Sleep(100 * time.Millisecond)
        fmt.Println("Goroutine 1 done")
    }()

    go func() {
        defer wg.Done()
        fmt.Println("Goroutine 2 started")
        time.Sleep(200 * time.Millisecond)
        fmt.Println("Goroutine 2 done")
    }()

    go func() {
        defer wg.Done()
        fmt.Println("Goroutine 3 started")
        time.Sleep(50 * time.Millisecond)
        fmt.Println("Goroutine 3 done")
    }()

    // ---- Wait for all goroutines to finish ----
    wg.Wait()
    fmt.Println("All goroutines finished")

    // ---- WaitGroup with loop ----
    var wg2 sync.WaitGroup

    for i := 1; i <= 5; i++ {
        wg2.Add(1)
        go func(n int) {
            defer wg2.Done()
            fmt.Printf("Worker %d started\n", n)
            time.Sleep(time.Duration(50*n) * time.Millisecond)
            fmt.Printf("Worker %d done\n", n)
        }(i)
    }

    wg2.Wait()
    fmt.Println("All workers finished")

    // ---- WaitGroup with error handling ----
    var wg3 sync.WaitGroup
    errors := make(chan error, 3)

    for i := 0; i < 3; i++ {
        wg3.Add(1)
        go func(n int) {
            defer wg3.Done()
            if n == 1 {
                errors <- fmt.Errorf("error in worker %d", n)
                return
            }
            fmt.Printf("Worker %d success\n", n)
        }(i)
    }

    wg3.Wait()
    close(errors)

    for err := range errors {
        fmt.Println("Error:", err)
    }
}

