    var wg sync.WaitGroup

    for i := 1; i <= 4; i++ {
        wg.Add(1)
        go func(n int) {
            defer wg.Done()
            fmt.Printf("Goroutine %d started\n", n)
            time.Sleep(time.Duration(50*n) * time.Millisecond)
            fmt.Printf("Goroutine %d done\n", n)
        }(i)
